const rows = $input.all().map(item => item.json);

// ======================================================
// НАСТРОЙКИ
// ======================================================

// Основной блок со швеями.
const sewingRowPairs = [
  { nameRow: 7, statusRow: 8 },
  { nameRow: 10, statusRow: 11 },
];

// Нижний блок с другим персоналом.
const staffRowPairs = [
  { nameRow: 14, statusRow: 15 },
  { nameRow: 17, statusRow: 18 },
];

// Игнорируем только номер строки и вертикальную ячейку "ШВЕИ".
// Поля "18", "col_8", "col_10" не удаляем:
// в них находятся реальные сотрудники.
const ignoredColumns = new Set([
  "row_number",
  "col_1",
]);

// ======================================================
// ФУНКЦИИ
// ======================================================

function findRow(rowNumber) {
  return rows.find(
    row => Number(row.row_number) === Number(rowNumber)
  );
}

function isEmpty(value) {
  if (value === null || value === undefined) {
    return true;
  }

  const text = String(value).trim().toLowerCase();

  return (
    text === "" ||
    text === "empty" ||
    text === "undefined" ||
    text === "null"
  );
}

function cleanEmployeeName(value) {
  return String(value)
    .replace(
      /\s*-\s*(швачка|швея|закрійник|закройщик|пакувальниця|упаковщица|фурнітурниця|фурнитурщица|прибиральниця|уборщица|різноробочий|разнорабочий|майстер|мастер).*$/i,
      ""
    )
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeStatus(value) {
  if (isEmpty(value)) {
    return "Не внесено";
  }

  return String(value).trim();
}

function isWorkingStatus(status) {
  const value = String(status).trim().toLowerCase();

  return (
    value.includes("работает") ||
    value.includes("працює") ||
    value === "+" ||
    value === "так" ||
    value === "да"
  );
}

function isDowntimeStatus(status) {
  const value = String(status).trim().toLowerCase();

  return (
    value.includes("простой") ||
    value.includes("простій")
  );
}

function isDayOffStatus(status) {
  const value = String(status).trim().toLowerCase();

  return (
    value.includes("выходн") ||
    value.includes("вихідн") ||
    value.includes("отпуск") ||
    value.includes("відпуст") ||
    value.includes("больнич") ||
    value.includes("лікарнян") ||
    value.includes("отсутств") ||
    value.includes("відсут")
  );
}

function formatList(array) {
  return array.length
    ? array.map(item => `• ${item}`).join("\n")
    : "—";
}

// Проверяем, похоже ли значение на имя сотрудника.
function looksLikeEmployee(value) {
  if (isEmpty(value)) {
    return false;
  }

  const text = String(value).trim().toLowerCase();

  const forbiddenValues = [
    "швеи",
    "швеї",
    "цех",
    "мастер",
    "дата",
    "харьков мост",
    "всего посадочных мест",
    "на выходном",
    "работает",
    "простой",
  ];

  if (forbiddenValues.includes(text)) {
    return false;
  }

  return (
    text.includes(" - ") ||
    /[А-ЯІЇЄҐA-Z][а-яіїєґa-z]+\s+[А-ЯІЇЄҐA-Z]\.\s*[А-ЯІЇЄҐA-Z]\./i.test(text)
  );
}

// ======================================================
// ИЗВЛЕЧЕНИЕ СОТРУДНИКОВ
// ======================================================

function extractEmployees(rowPairs, allowEmptySeats = false) {
  const result = [];

  for (const pair of rowPairs) {
    const namesRow = findRow(pair.nameRow);
    const statusesRow = findRow(pair.statusRow);

    if (!namesRow || !statusesRow) {
      continue;
    }

    const columns = new Set([
      ...Object.keys(namesRow),
      ...Object.keys(statusesRow),
    ]);

    for (const column of columns) {
      if (ignoredColumns.has(column)) {
        continue;
      }

      const rawName = namesRow[column];
      const rawStatus = statusesRow[column];

      const nameIsEmpty = isEmpty(rawName);
      const statusIsEmpty = isEmpty(rawStatus);

      // Полностью пустая пара.
      if (nameIsEmpty && statusIsEmpty) {
        continue;
      }

      // Если имя есть, но это не сотрудник — пропускаем.
      if (!nameIsEmpty && !looksLikeEmployee(rawName)) {
        continue;
      }

      // В нижнем блоке не учитываем пустые посадочные места.
      if (nameIsEmpty && !allowEmptySeats) {
        continue;
      }

      const status = normalizeStatus(rawStatus);

      result.push({
        name: nameIsEmpty
          ? "Вільне посадкове місце"
          : cleanEmployeeName(rawName),

        fullName: nameIsEmpty
          ? ""
          : String(rawName).trim(),

        status,
        column,
        nameRow: pair.nameRow,
        statusRow: pair.statusRow,
        isEmptySeat: nameIsEmpty,
      });
    }
  }

  return result;
}

// ======================================================
// ШВЕИ
// ======================================================

const sewingEmployees = extractEmployees(
  sewingRowPairs,
  true
);

const sewingWorking = [];
const sewingDowntimeEmployees = [];
const sewingDayOff = [];
const sewingUnknown = [];

let emptySeatDowntime = 0;

for (const employee of sewingEmployees) {
  if (isWorkingStatus(employee.status)) {
    if (employee.isEmptySeat) {
      sewingUnknown.push(
        `Вільне посадкове місце — ${employee.status}`
      );
    } else {
      sewingWorking.push(employee.name);
    }

    continue;
  }

  if (isDowntimeStatus(employee.status)) {
    if (employee.isEmptySeat) {
      emptySeatDowntime++;
    } else {
      sewingDowntimeEmployees.push(employee.name);
    }

    continue;
  }

  if (isDayOffStatus(employee.status)) {
    const label = employee.isEmptySeat
      ? "Вільне посадкове місце"
      : employee.name;

    sewingDayOff.push(
      `${label} — ${employee.status}`
    );

    continue;
  }

  const label = employee.isEmptySeat
    ? "Вільне посадкове місце"
    : employee.name;

  sewingUnknown.push(
    employee.status === "Не внесено"
      ? label
      : `${label} — ${employee.status}`
  );
}

const sewingDowntimeTotal =
  sewingDowntimeEmployees.length + emptySeatDowntime;

const sewingTotal =
  sewingWorking.length +
  sewingDowntimeTotal +
  sewingDayOff.length +
  sewingUnknown.length;

const sewingAttendance = sewingTotal
  ? Math.round(
      (sewingWorking.length / sewingTotal) * 100
    )
  : 0;

// ======================================================
// ДРУГОЙ ПЕРСОНАЛ
// ======================================================

const staffEmployees = extractEmployees(
  staffRowPairs,
  false
);

const staffWorking = [];
const staffDowntime = [];
const staffDayOff = [];
const staffUnknown = [];

for (const employee of staffEmployees) {
  if (isWorkingStatus(employee.status)) {
    staffWorking.push(employee.name);
    continue;
  }

  if (isDowntimeStatus(employee.status)) {
    staffDowntime.push(employee.name);
    continue;
  }

  if (isDayOffStatus(employee.status)) {
    staffDayOff.push(
      `${employee.name} — ${employee.status}`
    );

    continue;
  }

  staffUnknown.push(
    employee.status === "Не внесено"
      ? employee.name
      : `${employee.name} — ${employee.status}`
  );
}

const staffTotal = staffEmployees.length;

// ======================================================
// ДАТА
// ======================================================

function getDateFromSheet() {
  for (const row of rows) {
    for (const value of Object.values(row)) {
      if (isEmpty(value)) {
        continue;
      }

      const text = String(value).trim();

      if (/^\d{2}\.\d{2}\.\d{4}$/.test(text)) {
        return text;
      }
    }
  }

  return new Intl.DateTimeFormat("uk-UA", {
    timeZone: "Europe/Kyiv",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).format(new Date());
}

const reportDate = getDateFromSheet();

// ======================================================
// ТЕКСТ ПРОСТОЯ
// ======================================================

const sewingDowntimeLines = [];

for (const name of sewingDowntimeEmployees) {
  sewingDowntimeLines.push(`• ${name}`);
}

if (emptySeatDowntime > 0) {
  sewingDowntimeLines.push(
    `• Вільні посадкові місця — ${emptySeatDowntime}`
  );
}

const sewingDowntimeText =
  sewingDowntimeLines.length
    ? sewingDowntimeLines.join("\n")
    : "—";

// ======================================================
// TELEGRAM-СООБЩЕНИЕ
// ======================================================

const staffSection = staffTotal
  ? `

👷 ІНШИЙ ПЕРСОНАЛ

👥 Усього працівників: ${staffTotal}

✅ Працює — ${staffWorking.length}:
${formatList(staffWorking)}

⏸ Простій — ${staffDowntime.length}:
${formatList(staffDowntime)}

🏠 Вихідний / відсутні — ${staffDayOff.length}:
${formatList(staffDayOff)}

⚠️ Статус не внесено — ${staffUnknown.length}:
${formatList(staffUnknown)}`
  : "";

const message = `📋 Звіт по виробництву
📅 ${reportDate}

🧵 ШВЕЇ

👥 Усього посадкових місць: ${sewingTotal}

✅ Працює — ${sewingWorking.length}:
${formatList(sewingWorking)}

⏸ Простій — ${sewingDowntimeTotal}:
${sewingDowntimeText}

🏠 Вихідний / відсутні — ${sewingDayOff.length}:
${formatList(sewingDayOff)}

⚠️ Статус не внесено — ${sewingUnknown.length}:
${formatList(sewingUnknown)}

📊 Завантаженість: ${sewingAttendance}%${staffSection}`;

// ======================================================
// OUTPUT
// ======================================================

return [
  {
    json: {
      message,
      reportDate,

      sewing: {
        totalSeats: sewingTotal,
        working: sewingWorking.length,
        downtime: sewingDowntimeTotal,
        emptySeatDowntime,
        employeeDowntime:
          sewingDowntimeEmployees.length,
        dayOff: sewingDayOff.length,
        unknown: sewingUnknown.length,
        attendance: sewingAttendance,
        workingNames: sewingWorking,
        employees: sewingEmployees,
      },

      staff: {
        total: staffTotal,
        working: staffWorking.length,
        downtime: staffDowntime.length,
        dayOff: staffDayOff.length,
        unknown: staffUnknown.length,
        employees: staffEmployees,
      },
    },
  },
];
